//! Runie Terminal — Non-blocking event loop with render actor
//!
//! Architecture (impossible to block by design):
//!   1. Event loop: single-threaded async, only async ops
//!   2. State: owned by event loop, mutable borrow per event
//!   3. Snapshot: immutable frame description (the UI DSL)
//!   4. Render actor: owns Terminal, receives Snapshots via channel
//!   5. If render is slow, old Snapshots are dropped — event loop never waits

use crossterm::event::{Event, EventStream, KeyCode, KeyEvent, KeyEventKind, KeyModifiers};
use futures::StreamExt;
use ratatui::{backend::CrosstermBackend, Terminal};
use runie_agent::{AgentCommand, run_agent_turn};
use runie_core::{AppState, Event as CoreEvent, Snapshot};
use std::{io, time::Duration};
use tokio::sync::mpsc;

const ANIM_MS: u64 = 200;

struct Cleanup;

impl Drop for Cleanup {
    fn drop(&mut self) {
        let _ = crossterm::execute!(std::io::stdout(), crossterm::terminal::LeaveAlternateScreen);
        let _ = crossterm::terminal::disable_raw_mode();
    }
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() -> io::Result<()> {
    let _cleanup = Cleanup;
    let terminal = setup_terminal()?;
    let state = AppState::default();

    let (input_tx, input_rx) = mpsc::channel::<CoreEvent>(100);
    let (agent_tx, agent_rx) = mpsc::channel::<CoreEvent>(100);
    let (cmd_tx, cmd_rx) = mpsc::channel::<AgentCommand>(10);
    let (render_tx, render_rx) = mpsc::channel::<Snapshot>(1);

    tokio::spawn(agent_loop(cmd_rx, agent_tx));
    tokio::spawn(input_reader(input_tx));
    tokio::spawn(render_task(terminal, render_rx));

    event_loop(state, input_rx, agent_rx, cmd_tx, render_tx).await
}

fn setup_terminal() -> io::Result<Terminal<CrosstermBackend<std::io::Stdout>>> {
    crossterm::terminal::enable_raw_mode()?;
    crossterm::execute!(
        std::io::stdout(),
        crossterm::terminal::EnterAlternateScreen,
        crossterm::event::EnableBracketedPaste,
    )?;
    Terminal::new(CrosstermBackend::new(std::io::stdout()))
}

async fn render_task(
    mut terminal: Terminal<CrosstermBackend<std::io::Stdout>>,
    mut render_rx: mpsc::Receiver<Snapshot>,
) {
    while let Some(snap) = render_rx.recv().await {
        let _ = terminal.draw(|f| runie_tui::ui::draw_snapshot(f, &snap));
    }
}

async fn input_reader(input_tx: mpsc::Sender<CoreEvent>) {
    let mut reader = EventStream::new();
    while let Some(Ok(event)) = reader.next().await {
        if let Some(evt) = convert_event(&event) {
            let is_quit = matches!(&evt, CoreEvent::Quit | CoreEvent::Reset);
            if input_tx.send(evt).await.is_err() { break; }
            if is_quit { break; }
        }
    }
}

async fn event_loop(
    mut state: AppState,
    mut input_rx: mpsc::Receiver<CoreEvent>,
    mut agent_rx: mpsc::Receiver<CoreEvent>,
    cmd_tx: mpsc::Sender<AgentCommand>,
    render_tx: mpsc::Sender<Snapshot>,
) -> io::Result<()> {
    let mut anim = tokio::time::interval(Duration::from_millis(ANIM_MS));

    // Initial draw so the user sees the app immediately, without waiting
    // for the first keyboard event.
    state.ensure_fresh();
    let _ = render_tx.try_send(state.snapshot());

    loop {
        tokio::select! {
            biased;

            Some(evt) = input_rx.recv() => {
                let was_submit = matches!(evt, CoreEvent::Submit);
                let was_followup = matches!(evt, CoreEvent::FollowUp);
                let was_quit = matches!(evt, CoreEvent::Quit | CoreEvent::Reset);
                state.update(evt);
                if was_submit || was_followup {
                    spawn_if_queued(&mut state, &cmd_tx).await;
                }
                if was_quit {
                    return Ok(());
                }
            }

            Some(evt) = agent_rx.recv() => {
                let was_done = matches!(evt, CoreEvent::AgentDone { .. } | CoreEvent::AgentError { .. });
                state.update(evt);
                if was_done {
                    spawn_if_queued(&mut state, &cmd_tx).await;
                }
            }

            _ = anim.tick() => {
                state.tick_animation();
            }
        }

        state.ensure_fresh();
        let snap = state.snapshot();
        if render_tx.try_send(snap).is_err() {
            // Render task is behind — old snapshot dropped, latest will draw
        }
    }
}

async fn agent_loop(mut cmd_rx: mpsc::Receiver<AgentCommand>, agent_tx: mpsc::Sender<CoreEvent>) {
    while let Some(cmd) = cmd_rx.recv().await {
        let agent_tx_clone = agent_tx.clone();
        let cmd_id = cmd.id.clone();

        let result = run_agent_turn(
            &cmd,
            |evt| {
                let tx = agent_tx_clone.clone();
                let _ = tx.try_send(evt);
            },
            5,
        ).await;

        if let Err(e) = result {
            let _ = agent_tx.send(CoreEvent::AgentError {
                id: cmd_id,
                message: format!("Agent error: {}", e),
            }).await;
        }
    }
}

async fn spawn_if_queued(state: &mut AppState, cmd_tx: &mpsc::Sender<AgentCommand>) {
    if let Some((content, id)) = state.peek_queue() {
        let content = content.clone();
        let id = id.clone();
        state.pop_queue();
        state.streaming = true;
        state.turn_active = true;
        state.inflight += 1;
        let _ = cmd_tx.send(AgentCommand {
            content,
            id,
            provider: state.current_provider.clone(),
            model: state.current_model.clone(),
        }).await;
    }
}

#[cfg(test)]
mod tests {
    use crossterm::event::{KeyCode, KeyEvent, KeyModifiers, KeyEventKind};

    #[test]
    fn animation_interval_is_200ms() {
        assert_eq!(super::ANIM_MS, 200, "ANIM_MS must be 200ms for visible braille spinner, got {}", super::ANIM_MS);
    }

    #[test]
    fn ctrl_shift_e_converts_to_toggle_expand() {
        let key = KeyEvent::new(KeyCode::Char('E'), KeyModifiers::CONTROL | KeyModifiers::SHIFT);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::ToggleExpand)), "Ctrl+Shift+E should map to ToggleExpand, got {:?}", result);
    }

    #[test]
    fn ctrl_e_converts_to_toggle_expand_for_terminals_without_shift() {
        let key = KeyEvent::new(KeyCode::Char('e'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::ToggleExpand)), "Ctrl+E should map to ToggleExpand (terminal fallback), got {:?}", result);
    }

    #[test]
    fn ctrl_c_converts_to_quit() {
        let key = KeyEvent::new(KeyCode::Char('c'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Quit)), "Ctrl+C should map to Quit");
    }

    #[test]
    fn plain_e_not_converted() {
        let key = KeyEvent::new(KeyCode::Char('e'), KeyModifiers::empty());
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Input('e'))), "Plain e should map to Input");
    }

    #[test]
    fn ctrl_e_does_not_conflict_with_quit() {
        let key = KeyEvent::new(KeyCode::Char('e'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(!matches!(result, Some(super::CoreEvent::Quit)), "Ctrl+E should NOT map to Quit");
    }

    #[tokio::test]
    async fn spawn_if_queued_sets_turn_active_and_inflight() {
        let (tx, mut rx) = tokio::sync::mpsc::channel::<super::AgentCommand>(10);
        let mut state = super::AppState::default();
        state.request_queue.push_back(("hello".to_string(), "req.0".to_string()));

        assert!(!state.turn_active);
        assert_eq!(state.inflight, 0);

        super::spawn_if_queued(&mut state, &tx).await;

        assert!(state.turn_active, "spawn_if_queued must set turn_active");
        assert_eq!(state.inflight, 1, "spawn_if_queued must increment inflight");
        assert!(state.request_queue.is_empty(), "Message should be popped from request_queue");

        let cmd = rx.try_recv().expect("Command should be sent to agent");
        assert_eq!(cmd.content, "hello");
    }

    #[tokio::test]
    async fn spawn_if_queued_noop_when_queue_empty() {
        let (tx, _rx) = tokio::sync::mpsc::channel::<super::AgentCommand>(10);
        let mut state = super::AppState::default();

        super::spawn_if_queued(&mut state, &tx).await;

        assert!(!state.turn_active);
        assert_eq!(state.inflight, 0);
    }

    #[test]
    fn ctrl_shift_e_on_repeat_kind_still_works() {
        let key = KeyEvent::new_with_kind(KeyCode::Char('E'), KeyModifiers::CONTROL | KeyModifiers::SHIFT, KeyEventKind::Repeat);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::ToggleExpand)), "Ctrl+Shift+E with Repeat kind should still map to ToggleExpand, got {:?}", result);
    }

    #[test]
    fn ctrl_e_on_repeat_kind_still_works() {
        let key = KeyEvent::new_with_kind(KeyCode::Char('e'), KeyModifiers::CONTROL, KeyEventKind::Repeat);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::ToggleExpand)), "Ctrl+E with Repeat kind should still map to ToggleExpand, got {:?}", result);
    }

    #[test]
    fn ctrl_z_converts_to_undo() {
        let key = KeyEvent::new(KeyCode::Char('z'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Undo)), "Ctrl+Z should map to Undo");
    }

    #[test]
    fn ctrl_y_converts_to_redo() {
        let key = KeyEvent::new(KeyCode::Char('y'), KeyModifiers::CONTROL);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Redo)), "Ctrl+Y should map to Redo");
    }

    #[test]
    fn alt_b_converts_to_word_left() {
        let key = KeyEvent::new(KeyCode::Char('b'), KeyModifiers::ALT);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::CursorWordLeft)), "Alt+B should map to CursorWordLeft");
    }

    #[test]
    fn alt_f_converts_to_word_right() {
        let key = KeyEvent::new(KeyCode::Char('f'), KeyModifiers::ALT);
        let event = crossterm::event::Event::Key(key);
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::CursorWordRight)), "Alt+F should map to CursorWordRight");
    }

    #[test]
    fn bracketed_paste_converts_to_paste_event() {
        let event = crossterm::event::Event::Paste("hello world".to_string());
        let result = super::convert_event(&event);
        assert!(matches!(result, Some(super::CoreEvent::Paste(s)) if s == "hello world"), "Paste event should map to CoreEvent::Paste");
    }
}

fn convert_event(event: &Event) -> Option<CoreEvent> {
    log_key_event(event);
    match event {
        Event::Paste(data) => {
            Some(CoreEvent::Paste(data.clone()))
        }
        Event::Key(key) if key.kind == KeyEventKind::Press || key.kind == KeyEventKind::Repeat => {
            map_key_event(key)
        }
        _ => None,
    }
}

fn log_key_event(event: &Event) {
    if let Event::Key(key) = event {
        if std::env::var("RUNIE_DEBUG").is_ok() {
            use std::io::Write;
            let _ = std::fs::OpenOptions::new()
                .create(true)
                .append(true)
                .open("/tmp/runie_keys.log")
                .and_then(|mut f| writeln!(f, "{:?}", key));
        }
    }
}

fn map_key_event(key: &KeyEvent) -> Option<CoreEvent> {
    if key.modifiers.contains(KeyModifiers::CONTROL) {
        map_ctrl_key(key.code)
    } else if key.modifiers.contains(KeyModifiers::ALT) {
        map_alt_key(key.code)
    } else if key.modifiers.contains(KeyModifiers::SHIFT) {
        map_shift_key(key.code)
    } else {
        map_plain_key(key.code)
    }
}

fn map_ctrl_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        // Ctrl+E: toggle expand (also Ctrl+Shift+E on terminals with proper modifier)
        KeyCode::Char('e') | KeyCode::Char('E') => Some(CoreEvent::ToggleExpand),
        // Ctrl+J: newline (line feed)
        KeyCode::Char('j') | KeyCode::Char('J') => Some(CoreEvent::Newline),
        // Ctrl+A: move cursor to start (Emacs)
        KeyCode::Char('a') | KeyCode::Char('A') => Some(CoreEvent::CursorStart),
        // Ctrl+B: move cursor backward (Emacs)
        KeyCode::Char('b') | KeyCode::Char('B') => Some(CoreEvent::CursorLeft),
        // Ctrl+F: move cursor forward (Emacs)
        KeyCode::Char('f') | KeyCode::Char('F') => Some(CoreEvent::CursorRight),
        // Ctrl+W: delete word (Emacs)
        KeyCode::Char('w') | KeyCode::Char('W') => Some(CoreEvent::DeleteWord),
        // Ctrl+K: delete to end (Emacs)
        KeyCode::Char('k') | KeyCode::Char('K') => Some(CoreEvent::DeleteToEnd),
        // Ctrl+U: delete to start (Emacs)
        KeyCode::Char('u') | KeyCode::Char('U') => Some(CoreEvent::DeleteToStart),
        // Ctrl+D: delete char at cursor (Emacs)
        KeyCode::Char('d') | KeyCode::Char('D') => Some(CoreEvent::KillChar),
        // Ctrl+Z: undo
        KeyCode::Char('z') | KeyCode::Char('Z') => Some(CoreEvent::Undo),
        // Ctrl+Y: redo
        KeyCode::Char('y') | KeyCode::Char('Y') => Some(CoreEvent::Redo),
        // Ctrl+C: quit
        KeyCode::Char('c') | KeyCode::Char('C') => Some(CoreEvent::Quit),
        // Ctrl+S: abort
        KeyCode::Char('s') | KeyCode::Char('S') => Some(CoreEvent::Abort),
        _ => None,
    }
}

fn map_alt_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        KeyCode::Enter => Some(CoreEvent::FollowUp),
        // Alt+B: word backward
        KeyCode::Char('b') | KeyCode::Char('B') => Some(CoreEvent::CursorWordLeft),
        // Alt+F: word forward
        KeyCode::Char('f') | KeyCode::Char('F') => Some(CoreEvent::CursorWordRight),
        _ => None,
    }
}

fn map_shift_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        // Shift+Enter: newline
        KeyCode::Enter => Some(CoreEvent::Newline),
        _ => None,
    }
}

fn map_plain_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        KeyCode::Esc => Some(CoreEvent::Abort),
        KeyCode::Char('\t') | KeyCode::Tab | KeyCode::BackTab => Some(CoreEvent::Input('\t')),
        KeyCode::Char(c) => Some(CoreEvent::Input(c)),
        KeyCode::Backspace => Some(CoreEvent::Backspace),
        KeyCode::Enter => Some(CoreEvent::Submit),
        KeyCode::Up => Some(CoreEvent::HistoryPrev),
        KeyCode::Down => Some(CoreEvent::HistoryNext),
        KeyCode::Left => Some(CoreEvent::CursorLeft),
        KeyCode::Right => Some(CoreEvent::CursorRight),
        KeyCode::Home => Some(CoreEvent::CursorStart),
        KeyCode::End => Some(CoreEvent::CursorEnd),
        KeyCode::Delete => Some(CoreEvent::KillChar),
        _ => None,
    }
}

//! View — renders Snapshot to terminal via ratatui
//!
//! Architecture: the event loop builds immutable Snapshots;
//! the render actor draws them. No state mutations, no blocking
//! I/O, no caching — pure functions from Snapshot to Frame.
//!
//! DESIGN SYSTEM RULE: all colors, glyphs, and styles come from
//! crate::theme only. No literals, no hardcoded values.

use ratatui::{
    layout::{Constraint, Direction, Layout, Rect},
    style::Color,
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Scrollbar, ScrollbarOrientation, ScrollbarState, Wrap},
    Frame,
};

fn vstack(area: Rect, heights: &[Constraint]) -> Vec<Rect> {
    Layout::default().direction(Direction::Vertical).constraints(heights).split(area).to_vec()
}

fn hstack(area: Rect, widths: &[Constraint]) -> Vec<Rect> {
    Layout::default().direction(Direction::Horizontal).constraints(widths).split(area).to_vec()
}

use runie_core::{Element, Snapshot};

use crate::markdown::{extract_code_blocks, md_to_spans, parse_inline_markdown_with_color, CodeBlock};
use crate::syntax::highlight_code;
use runie_core::format_timestamp;
use crate::theme::{
    C, GLYPH_USER, GLYPH_AGENT, GLYPH_INDENT,
    GLYPH_SELECTED, GLYPH_UNSELECTED, PANEL_INPUT,
    SCROLLBAR_TRACK, SCROLLBAR_THUMB,
    code_header_label, thinking_line, tool_running_line, tool_done_header,
    tool_summary_line, turn_complete_line, thought_summary_line,
    style_user, style_agent, style_thought, style_thinking, style_thought_summary,
    style_tool_running, style_tool_header, style_tool_output, style_tool_summary,
    style_turn_complete, style_empty_state, style_timestamp, style_status_idle,
    style_status_active, style_border, style_border_flash,
    style_code_header, style_input_cursor, style_placeholder, style_hint,
    style_popup_selected, style_popup_unselected, style_popup_border,
};

/// Draw a Snapshot to the terminal. Pure function — no mutable state.
pub fn draw_snapshot(f: &mut Frame, snap: &Snapshot) {
    let c = vstack(f.area(), &[
        Constraint::Min(3),
        Constraint::Length(1),
        Constraint::Length(3),
        Constraint::Length(1),
    ]);
    messages(f, snap, c[0]);
    status(f, snap, c[1]);
    input(f, snap, c[2]);
    hints(f, snap, c[3]);
    at_suggestions(f, snap);
}

/// Legacy entry point for code that still builds AppState directly.
pub fn view(f: &mut Frame, state: &mut runie_core::AppState) {
    state.ensure_fresh();
    let snap = state.snapshot();
    draw_snapshot(f, &snap);
}

fn status(f: &mut Frame, snap: &Snapshot, area: Rect) {
    let tokens: usize = snap.elements.iter().map(estimate_element_tokens).sum();
    let left_text = build_status_text(snap);
    let queue_part = if snap.queue_count > 0 {
        format!(" · {} queued", snap.queue_count)
    } else {
        String::new()
    };
    let right_text = format!("{} tok{}", tokens, queue_part);

    let h = hstack(area, &[
        Constraint::Min(0),
        Constraint::Length(right_text.len() as u16),
    ]);

    let status_style = if snap.turn_active {
        style_status_active()
    } else {
        style_status_idle()
    };

    f.render_widget(Paragraph::new(left_text).style(status_style), h[0]);
    f.render_widget(Paragraph::new(right_text).style(style_timestamp()), h[1]);
}

fn build_status_text(snap: &Snapshot) -> String {
    let mut parts = Vec::new();
    parts.push(format!("{}/{}", snap.provider, snap.model));
    if snap.turn_active {
        if let Some(elapsed) = snap.turn_elapsed_secs {
            parts.push(runie_core::labels::action_text(
                snap.spinner_frame, "Working", elapsed,
            ));
        } else {
            parts.push(format!("{} Working...", snap.spinner_frame));
        }
    }
    parts.join(" · ")
}

fn messages(f: &mut Frame, snap: &Snapshot, area: Rect) {
    if snap.elements.is_empty() {
        render_empty_state(f, area);
        return;
    }
    render_message_content(f, snap, area);
}

fn render_empty_state(f: &mut Frame, area: Rect) {
    let hint = Line::from("Type a message to start...").style(style_empty_state());
    f.render_widget(Paragraph::new(hint), area);
}

fn render_message_content(f: &mut Frame, snap: &Snapshot, area: Rect) {
    let height = area.height as usize;
    let total_lines = snap.total_lines;
    if height == 0 || total_lines == 0 {
        return;
    }

    let show_bar = total_lines > height;
    let content_width = if show_bar {
        area.width.saturating_sub(1)
    } else {
        area.width
    };

    let h = hstack(area, &[Constraint::Length(content_width), Constraint::Min(0)]);
    let lines = build_lines(snap);
    let offset = snap.scroll_offset(height);
    f.render_widget(
        Paragraph::new(lines)
            .scroll((offset, 0))
            .wrap(Wrap { trim: false }),
        h[0],
    );

    if show_bar {
        render_scrollbar(f, area, total_lines, offset, height);
    }
}

fn build_lines(snap: &Snapshot) -> Vec<Line<'_>> {
    let mut lines = Vec::with_capacity(snap.total_lines);
    for elem in &snap.elements {
        lines.extend(to_lines(elem, snap.spinner_frame));
    }
    lines
}

fn render_scrollbar(f: &mut Frame, area: Rect, total: usize, offset: u16, height: usize) {
    let scrollbar = Scrollbar::default()
        .orientation(ScrollbarOrientation::VerticalRight)
        .begin_symbol(None)
        .end_symbol(None)
        .track_symbol(Some(SCROLLBAR_TRACK))
        .thumb_symbol(SCROLLBAR_THUMB);

    let mut state = ScrollbarState::new(total)
        .position(offset as usize)
        .viewport_content_length(height);
    f.render_stateful_widget(scrollbar, area, &mut state);
}

fn to_lines<'a>(elem: &'a Element, _spinner_frame: char) -> Vec<Line<'a>> {
    use runie_core::Element::*;
    match elem {
        Spacer { .. } => vec![Line::from("")],
        UserMessage { content, timestamp } => render_message(content, *timestamp, GLYPH_USER, C.fg_bright),
        AgentMessage { content, timestamp } => render_agent_message(content, *timestamp),
        Thinking { started, .. } => vec![Line::from(
            thinking_line(started.elapsed().as_secs_f64())
        ).style(style_thinking())],
        ThoughtSummary { content, .. } => vec![Line::from(
            thought_summary_line(content.lines().next().unwrap_or(content))
        ).style(style_thought_summary())],
        ThoughtMarker { content, .. } => render_thought_marker(content),
        ToolRunning { name, started, .. } => vec![Line::from(
            tool_running_line(name, started.elapsed().as_secs_f64())
        ).style(style_tool_running())],
        ToolDone { name, duration_secs, output, .. } => render_tool_done(name, *duration_secs, output),
        ToolSummary { name, duration_secs, .. } => vec![Line::from(
            tool_summary_line(name, *duration_secs)
        ).style(style_tool_summary())],
        TurnComplete { duration_secs, .. } => vec![Line::from(
            turn_complete_line(*duration_secs)
        ).style(style_turn_complete())],
    }
}

fn render_message(content: &str, timestamp: f64, first_prefix: &'static str, base_color: Color) -> Vec<Line<'static>> {
    let mut lines = Vec::new();
    let ts_str = format_timestamp(timestamp);
    let base_style = if base_color == C.fg_bright { style_user() } else { style_agent() };
    for (i, line) in content.lines().enumerate() {
        let prefix = if i == 0 { first_prefix } else { GLYPH_INDENT };
        let ts = format!(" {:>5}", ts_str);
        let mut spans = vec![Span::styled(prefix, base_style)];
        spans.extend(md_to_spans(&parse_inline_markdown_with_color(line, base_color)));
        spans.push(Span::styled(ts, style_timestamp()));
        lines.push(Line::from(spans));
    }
    if lines.is_empty() {
        lines.push(Line::from(format!("{}{:>5}", first_prefix, ts_str)).style(base_style));
    }
    lines
}

fn render_list_item(item: &str, ordered: bool, idx: usize, is_first: bool, ts_str: &str) -> Line<'static> {
    let bullet = if ordered { format!("{}.", idx + 1) } else { "•".to_string() };
    let first_line_prefix = if is_first { format!("{} {}", GLYPH_AGENT, bullet) } else { format!("{} {}", GLYPH_INDENT, bullet) };
    let rest_prefix = format!("{}   ", GLYPH_INDENT);
    let first_ts = format!(" {:>5}", ts_str);
    let rest_ts = "      ".to_string();
    let lines: Vec<&str> = item.lines().collect();
    let mut text = String::new();
    for (j, line) in lines.iter().enumerate() {
        let prefix = if j == 0 { &first_line_prefix } else { &rest_prefix };
        let ts = if j == 0 { &first_ts } else { &rest_ts };
        text.push_str(prefix);
        text.push_str(line);
        text.push_str(ts);
        if j + 1 < lines.len() {
            text.push('\n');
        }
    }
    Line::from(text).style(style_agent())
}

fn render_code_block_lines(content: &str, lang: &str, ts_str: &str) -> Vec<Line<'static>> {
    let highlighted = highlight_code(content, lang);
    highlighted
        .into_iter()
        .map(|tokens| {
            let mut spans = vec![Span::raw(GLYPH_INDENT.to_string())];
            for token in tokens {
                spans.push(Span::styled(token.content, token.style));
            }
            spans.push(Span::raw(format!(" {:>5}", ts_str)));
            Line::from(spans)
        })
        .collect()
}

fn render_blockquote_lines(text: &str) -> Vec<Line<'static>> {
    text.lines()
        .map(|line| Line::from(format!("{}│ {}", GLYPH_INDENT, line)).style(style_agent()))
        .collect()
}

fn render_agent_message(content: &str, timestamp: f64) -> Vec<Line<'static>> {
    let blocks = extract_code_blocks(content);
    let mut lines = Vec::new();
    let mut is_first = true;
    let ts_str = format_timestamp(timestamp);

    for block in blocks {
        match block {
            CodeBlock::Text(text) => {
                for line in text.lines() {
                    lines.push(render_msg_line(line, timestamp, is_first));
                    is_first = false;
                }
            }
            CodeBlock::Code { lang, content } => {
                lines.push(render_code_header(&lang, is_first));
                is_first = false;
                lines.extend(render_code_block_lines(&content, &lang, &ts_str));
            }
            CodeBlock::List { ordered, items } => {
                for (i, item) in items.iter().enumerate() {
                    let rendered = render_list_item(item, ordered, i, is_first, &ts_str);
                    lines.push(rendered);
                    is_first = false;
                }
            }
            CodeBlock::Blockquote(text) => {
                lines.extend(render_blockquote_lines(&text));
                is_first = false;
            }
        }
    }
    if lines.is_empty() {
        lines.push(Line::from(format!("{}{:>5}", GLYPH_AGENT, ts_str)).style(style_agent()));
    }
    lines
}

fn render_code_header(lang: &str, is_first: bool) -> Line<'static> {
    let prefix = if is_first { GLYPH_AGENT } else { GLYPH_INDENT };
    Line::from(code_header_label(prefix, lang)).style(style_code_header())
}

fn render_msg_line(line: &str, timestamp: f64, is_first: bool) -> Line<'static> {
    let prefix = if is_first { GLYPH_AGENT } else { GLYPH_INDENT };
    let ts = format!(" {:>5}", format_timestamp(timestamp));
    let mut spans = vec![Span::styled(prefix.to_string(), style_agent())];
    spans.extend(md_to_spans(&parse_inline_markdown_with_color(line, C.fg)));
    spans.push(Span::styled(ts, style_timestamp()));
    Line::from(spans)
}

fn render_thought_marker(content: &str) -> Vec<Line<'static>> {
    content.lines()
        .map(|line| Line::from(line.to_string()).style(style_thought()))
        .collect()
}

fn render_tool_done(name: &str, duration_secs: f64, output: &str) -> Vec<Line<'static>> {
    let mut lines = vec![Line::from(tool_done_header(name, duration_secs))
        .style(style_tool_header())];
    if !output.is_empty() {
        // Check if output is a diff and render with highlighting
        if crate::diff::is_diff_output(output) {
            lines.extend(crate::diff::render_diff_text(output));
        } else {
            for line in output.lines() {
                lines.push(Line::from(line.to_string()).style(style_tool_output()));
            }
        }
    }
    lines
}

fn input(f: &mut Frame, snap: &Snapshot, area: Rect) {
    let border_style = if snap.input_flash > 0 {
        style_border_flash()
    } else {
        style_border()
    };
    let block = Block::default()
        .borders(Borders::ALL)
        .title(PANEL_INPUT)
        .border_style(border_style);
    let inner = block.inner(area);

    let spans = build_input_spans(snap);
    f.render_widget(Paragraph::new(Line::from(spans)).block(block), area);

    let cursor_x = inner.x + (GLYPH_USER.len() + snap.cursor_pos.min(snap.input.len())) as u16;
    f.set_cursor_position((cursor_x, inner.y));
}

fn build_input_spans(snap: &Snapshot) -> Vec<Span<'_>> {
    if snap.input.is_empty() && !snap.placeholder.is_empty() {
        return vec![
            Span::styled(GLYPH_USER, style_user()),
            Span::styled(snap.placeholder.clone(), style_placeholder()),
        ];
    }
    let cursor_pos = snap.cursor_pos.min(snap.input.len());
    let before = &snap.input[..cursor_pos];
    let (at_cursor, after) = if cursor_pos < snap.input.len() {
        let c = snap.input[cursor_pos..].chars().next().unwrap();
        let char_len = c.len_utf8();
        (c, &snap.input[cursor_pos + char_len..])
    } else {
        (' ', "")
    };
    vec![
        Span::styled(GLYPH_USER, style_user()),
        Span::styled(before, style_user()),
        Span::styled(at_cursor.to_string(), style_input_cursor()),
        Span::styled(after, style_user()),
    ]
}

fn hints(f: &mut Frame, _snap: &Snapshot, area: Rect) {
    let hints_text = "Ctrl+Shift+E=expand/collapse | Alt+Enter=follow-up | Esc=clear | Ctrl+C=quit";
    f.render_widget(Paragraph::new(hints_text).style(style_hint()), area);
}

fn at_suggestions(f: &mut Frame, snap: &Snapshot) {
    let suggestions = match &snap.at_suggestions {
        Some(s) if !s.is_empty() => s,
        _ => return,
    };
    let selected = snap.at_selected.unwrap_or(0).min(suggestions.len().saturating_sub(1));
    let area = f.area();
    let display_count = suggestions.len().min(8) as u16;
    let max_height = display_count + 4;
    let popup_area = Rect {
        x: area.x + 1,
        y: area.y + area.height.saturating_sub(4 + max_height),
        width: area.width.saturating_sub(2).max(20),
        height: max_height,
    };
    let mut lines: Vec<Line> = suggestions
        .iter()
        .take(8)
        .enumerate()
        .map(|(i, s)| {
            let prefix = if i == selected { GLYPH_SELECTED } else { GLYPH_UNSELECTED };
            let style = if i == selected { style_popup_selected() } else { style_popup_unselected() };
            Line::from(format!("{}{}", prefix, s)).style(style)
        })
        .collect();
    lines.push(Line::from(""));
    lines.push(
        Line::from("Tab=cycle Enter=insert Esc=close").style(style_hint()),
    );
    let block = Block::default()
        .borders(Borders::ALL)
        .title(format!(" @ files ({}) ", suggestions.len()))
        .border_style(style_popup_border());
    f.render_widget(Paragraph::new(lines).block(block), popup_area);
}

fn estimate_element_tokens(elem: &Element) -> usize {
    use runie_core::Element::*;
    match elem {
        UserMessage { content, .. }
        | AgentMessage { content, .. }
        | ThoughtMarker { content, .. } => content.len() / 4,
        Thinking { .. }
        | ThoughtSummary { .. }
        | ToolSummary { .. }
        | TurnComplete { .. } => 10,
        ToolRunning { .. } => 10,
        ToolDone { output, .. } => output.len() / 4 + 10,
        Spacer { .. } => 0,
    }
}

