use crate::model::{AppState, ChatMessage, DeliveryMode, Role};
use super::now;

impl AppState {
    pub(crate) fn queue_follow_up(&mut self) {
        if self.input.is_empty() {
            return;
        }
        let content = std::mem::take(&mut self.input).trim().to_string();
        if content.is_empty() {
            return;
        }
        self.message_queue.push(crate::model::QueuedMessage {
            content,
            kind: crate::model::QueuedMessageKind::FollowUp,
        });
        self.scroll = 0;
        self.mark_dirty();
    }

    pub(crate) fn abort_queue(&mut self) {
        if self.at_suggestions.take().is_some() {
            self.at_selected = None;
            self.last_at_query = None;
            self.mark_dirty();
            return;
        }
        for msg in self.message_queue.drain(..).rev() {
            if !self.input.is_empty() {
                self.input.push('\n');
            }
            self.input.push_str(&msg.content);
        }
        self.mark_dirty();
    }

    pub(crate) fn deliver_queued(&mut self) {
        if self.message_queue.is_empty() {
            return;
        }
        if self.try_deliver_steering() {
            return;
        }
        self.try_deliver_follow_up();
    }

    fn try_deliver_steering(&mut self) -> bool {
        let steering_indices: Vec<_> = self.message_queue.iter().enumerate()
            .filter(|(_, m)| m.kind == crate::model::QueuedMessageKind::Steering)
            .collect();
        if steering_indices.is_empty() {
            return false;
        }

        match self.steering_mode {
            DeliveryMode::OneAtATime => {
                // Deliver first steering message
                let idx = steering_indices[0].0;
                self.deliver_single_steering(idx);
            }
            DeliveryMode::All => {
                // Batch all steering messages into one call
                self.deliver_all_steering(&steering_indices);
            }
        }
        true
    }

    fn deliver_single_steering(&mut self, idx: usize) {
        let msg = self.message_queue.remove(idx);
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: msg.content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((msg.content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    fn deliver_all_steering(&mut self, indices: &[(usize, &crate::model::QueuedMessage)]) {
        if indices.is_empty() {
            return;
        }
        // Collect messages and sort by index descending to remove without shifting
        let mut to_deliver: Vec<_> = indices.iter().map(|(i, m)| (*i, m.content.clone())).collect();
        to_deliver.sort_by(|a, b| b.0.cmp(&a.0));

        // Join all content with newlines
        let combined_content = to_deliver.iter().map(|(_, c)| c).collect::<Vec<_>>().join("\n");

        // Remove messages from queue (descending order to preserve indices)
        for (idx, _) in &to_deliver {
            self.message_queue.remove(*idx);
        }

        // Create single message and request
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: combined_content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((combined_content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    fn try_deliver_follow_up(&mut self) {
        let follow_up_indices: Vec<_> = self.message_queue.iter().enumerate()
            .filter(|(_, m)| m.kind == crate::model::QueuedMessageKind::FollowUp)
            .collect();
        if follow_up_indices.is_empty() {
            return;
        }

        match self.follow_up_mode {
            DeliveryMode::OneAtATime => {
                // Deliver first follow-up message
                let idx = follow_up_indices[0].0;
                self.deliver_single_follow_up(idx);
            }
            DeliveryMode::All => {
                // Batch all follow-up messages into one call
                self.deliver_all_follow_up(&follow_up_indices);
            }
        }
    }

    fn deliver_single_follow_up(&mut self, idx: usize) {
        let msg = self.message_queue.remove(idx);
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: msg.content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((msg.content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    fn deliver_all_follow_up(&mut self, indices: &[(usize, &crate::model::QueuedMessage)]) {
        if indices.is_empty() {
            return;
        }
        // Collect messages and sort by index descending to remove without shifting
        let mut to_deliver: Vec<_> = indices.iter().map(|(i, m)| (*i, m.content.clone())).collect();
        to_deliver.sort_by(|a, b| b.0.cmp(&a.0));

        // Join all content with newlines
        let combined_content = to_deliver.iter().map(|(_, c)| c).collect::<Vec<_>>().join("\n");

        // Remove messages from queue (descending order to preserve indices)
        for (idx, _) in &to_deliver {
            self.message_queue.remove(*idx);
        }

        // Create single message and request
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: combined_content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((combined_content, id));
