        self.try_deliver_follow_up();
    }

    /// Deliver all queued messages in "All" mode (batched together)
    fn deliver_all_at_once(&mut self) {
        // Collect all messages first with their indices
        let mut all_messages: Vec<(usize, String, crate::model::QueuedMessageKind)> = self.message_queue.iter()
            .enumerate()
            .map(|(i, m)| (i, m.content.clone(), m.kind.clone()))
            .collect();

        // Separate by kind
        let steering_messages: Vec<(usize, String)> = all_messages.iter()
            .filter(|(_, _, kind)| *kind == crate::model::QueuedMessageKind::Steering)
            .map(|(i, content, _)| (*i, content.clone()))
            .collect();

        let follow_up_messages: Vec<(usize, String)> = all_messages.iter()
            .filter(|(_, _, kind)| *kind == crate::model::QueuedMessageKind::FollowUp)
            .map(|(i, content, _)| (*i, content.clone()))
            .collect();

        // Build combined content for each kind
        let mut steering_content = String::new();
        let mut follow_up_content = String::new();

        match self.steering_mode {
            DeliveryMode::OneAtATime => {
                if let Some((_, content)) = steering_messages.into_iter().next() {
                    steering_content = content;
                }
            }
            DeliveryMode::All => {
                steering_content = steering_messages.iter()
                    .map(|(_, c)| c.as_str())
                    .collect::<Vec<_>>()
                    .join("\n");
            }
        }

        match self.follow_up_mode {
            DeliveryMode::OneAtATime => {
                if let Some((_, content)) = follow_up_messages.into_iter().next() {
                    follow_up_content = content;
                }
            }
            DeliveryMode::All => {
                follow_up_content = follow_up_messages.iter()
                    .map(|(_, c)| c.as_str())
                    .collect::<Vec<_>>()
                    .join("\n");
            }
        }

        // Sort indices descending for safe removal
        let mut all_indices: Vec<usize> = all_messages.iter().map(|(i, _, _)| *i).collect();
        all_indices.sort_by(|a, b| b.cmp(a));

        // Remove all queued messages
        for idx in &all_indices {
            self.message_queue.remove(*idx);
        }

        // Create requests
        if !steering_content.is_empty() {
            let id = self.next_id();
            self.messages.push(ChatMessage {
                role: Role::User,
                content: steering_content.clone(),
                timestamp: now(),
                id: id.clone(),
            });
            self.request_queue.push_back((steering_content, id));
        }

        if !follow_up_content.is_empty() {
            let id = self.next_id();
            self.messages.push(ChatMessage {
                role: Role::User,
                content: follow_up_content.clone(),
                timestamp: now(),
                id: id.clone(),
            });
            self.request_queue.push_back((follow_up_content, id));
        }

        if !steering_content.is_empty() || !follow_up_content.is_empty() {
            self.scroll = 0;
            self.messages_changed();
        }
    }

    fn try_deliver_steering(&mut self) -> bool {
        let steering_messages: Vec<(usize, String)> = self.message_queue.iter().enumerate()
            .filter(|(_, m)| m.kind == crate::model::QueuedMessageKind::Steering)
            .map(|(i, m)| (i, m.content.clone()))
            .collect();
        if steering_messages.is_empty() {
            eprintln!("DEBUG try_deliver_steering: no steering found");
            return false;
        }
        eprintln!("DEBUG try_deliver_steering: found {} steering", steering_messages.len());

        match self.steering_mode {
            DeliveryMode::OneAtATime => {
                // Deliver first steering message
                let (idx, content) = steering_messages.into_iter().next().unwrap();
                self.deliver_single_steering(idx, content);
            }
            DeliveryMode::All => {
                // Batch all steering messages into one call
                self.deliver_all_steering(steering_messages);
            }
        }
        true
    }

    fn deliver_single_steering(&mut self, idx: usize, content: String) {
        let _ = self.message_queue.remove(idx);
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    fn deliver_all_steering(&mut self, messages: Vec<(usize, String)>) {
        if messages.is_empty() {
            return;
        }
        // Sort by index descending to remove without shifting
        let mut sorted = messages;
        sorted.sort_by(|a, b| b.0.cmp(&a.0));

        // Reverse for content join (maintains original queue order)
        let combined_content: String = sorted.iter().rev().map(|(_, c)| c.as_str()).collect::<Vec<_>>().join("\n").to_string();

        // Remove messages from queue (descending order to preserve indices)
        for (idx, _) in &sorted {
            self.message_queue.remove(*idx);
        }

        // Create single message and request
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: combined_content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((combined_content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    fn try_deliver_follow_up(&mut self) {
        let follow_up_messages: Vec<(usize, String)> = self.message_queue.iter().enumerate()
            .filter(|(_, m)| m.kind == crate::model::QueuedMessageKind::FollowUp)
            .map(|(i, m)| (i, m.content.clone()))
            .collect();
        if follow_up_messages.is_empty() {
            eprintln!("DEBUG try_deliver_follow_up: no follow-ups found, queue len={}", self.message_queue.len());
            return;
        }
        eprintln!("DEBUG try_deliver_follow_up: found {} follow-ups, mode={:?}", follow_up_messages.len(), self.follow_up_mode);

        match self.follow_up_mode {
            DeliveryMode::OneAtATime => {
                // Deliver first follow-up message
                let (idx, content) = follow_up_messages.into_iter().next().unwrap();
                self.deliver_single_follow_up(idx, content);
            }
            DeliveryMode::All => {
                // Batch all follow-up messages into one call
                self.deliver_all_follow_up(follow_up_messages);
            }
        }
    }

    fn deliver_single_follow_up(&mut self, idx: usize, content: String) {
        let _ = self.message_queue.remove(idx);
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    fn deliver_all_follow_up(&mut self, messages: Vec<(usize, String)>) {
        if messages.is_empty() {
            return;
        }
        // Sort by index descending to remove without shifting
        let mut sorted = messages;
        sorted.sort_by(|a, b| b.0.cmp(&a.0));

        // Reverse for content join (maintains original queue order)
        let combined_content: String = sorted.iter().rev().map(|(_, c)| c.as_str()).collect::<Vec<_>>().join("\n").to_string();

        // Remove messages from queue (descending order to preserve indices)
        for (idx, _) in &sorted {
            self.message_queue.remove(*idx);
        }

        // Create single message and request
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: combined_content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((combined_content, id));
        self.scroll = 0;
        self.messages_changed();
    }
}

