use crate::model::{AppState, ChatMessage, DeliveryMode, Role};
use super::now;

impl AppState {
    pub(crate) fn queue_follow_up(&mut self) {
        if self.input.is_empty() {
            return;
        }
        let content = std::mem::take(&mut self.input).trim().to_string();
        self.cursor_pos = 0;
        if content.is_empty() {
            return;
        }
        self.message_queue.push(crate::model::QueuedMessage {
            content,
            kind: crate::model::QueuedMessageKind::FollowUp,
        });
        self.scroll = 0;
        self.mark_dirty();
    }

    pub(crate) fn abort_queue(&mut self) {
        if self.at_suggestions.take().is_some() {
            self.at_selected = None;
            self.last_at_query = None;
            self.mark_dirty();
            return;
        }
        for msg in self.message_queue.drain(..).rev() {
            if !self.input.is_empty() {
                self.input.push('\n');
            }
            self.input.push_str(&msg.content);
        }
        self.mark_dirty();
    }

    pub(crate) fn deliver_queued(&mut self) {
        if self.message_queue.is_empty() {
            return;
        }
        // In "All" mode, batch everything together
        if self.steering_mode == DeliveryMode::All || self.follow_up_mode == DeliveryMode::All {
            self.deliver_all_at_once();
            return;
        }
        // In "OneAtATime" mode, deliver one category at a time
        if self.try_deliver_steering() {
            return;
        }
        self.try_deliver_follow_up();
    }

    /// Collect messages by kind for batched delivery.
    fn collect_by_kind(&self) -> (Vec<String>, Vec<String>) {
        let mut steering = Vec::new();
        let mut follow_up = Vec::new();
        for msg in &self.message_queue {
            match msg.kind {
                crate::model::QueuedMessageKind::Steering => steering.push(msg.content.clone()),
                crate::model::QueuedMessageKind::FollowUp => follow_up.push(msg.content.clone()),
            }
        }
        (steering, follow_up)
    }

    /// Deliver all queued messages in "All" mode (batched together).
    fn deliver_all_at_once(&mut self) {
        let (steering, follow_up) = self.collect_by_kind();

        let steering_content = match self.steering_mode {
            DeliveryMode::OneAtATime => steering.into_iter().next().unwrap_or_default(),
            DeliveryMode::All => steering.join("\n"),
        };

        let follow_up_content = match self.follow_up_mode {
            DeliveryMode::OneAtATime => follow_up.into_iter().next().unwrap_or_default(),
            DeliveryMode::All => follow_up.join("\n"),
        };

        // Clear the queue
        self.message_queue.clear();

        // Create requests for non-empty content
        if !steering_content.is_empty() {
            self.push_user_message(steering_content);
        }
        if !follow_up_content.is_empty() {
            self.push_user_message(follow_up_content);
        }

        if !steering_content.is_empty() || !follow_up_content.is_empty() {
            self.scroll = 0;
            self.messages_changed();
        }
    }

    fn push_user_message(&mut self, content: String) {
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((content, id));
    }

    fn try_deliver_steering(&mut self) -> bool {
        if let Some(idx) = self.message_queue.iter().position(|m| m.kind == crate::model::QueuedMessageKind::Steering) {
            let content = self.message_queue.remove(idx).content;
            self.push_user_message(content);
            self.scroll = 0;
            self.messages_changed();
            true
        } else {
            false
        }
    }

    fn try_deliver_follow_up(&mut self) {
        if let Some(idx) = self.message_queue.iter().position(|m| m.kind == crate::model::QueuedMessageKind::FollowUp) {
            let content = self.message_queue.remove(idx).content;
            self.push_user_message(content);
            self.scroll = 0;
            self.messages_changed();
        }
    }
}

