/// Deliver all queued messages in "All" mode (batched together).
fn deliver_all_at_once(&mut self) {
    let (steering, follow_up) = self.collect_by_kind();

    let steering_content = match self.steering_mode {
        DeliveryMode::OneAtATime => steering.into_iter().next().unwrap_or_default(),
        DeliveryMode::All => steering.join("\n"),
    };

    let follow_up_content = match self.follow_up_mode {
        DeliveryMode::OneAtATime => follow_up.into_iter().next().unwrap_or_default(),
        DeliveryMode::All => follow_up.join("\n"),
    };

    // Clear the queue
    self.message_queue.clear();

    // Create requests for non-empty content
    if !steering_content.is_empty() {
        self.push_user_message(steering_content);
    }
    if !follow_up_content.is_empty() {
        self.push_user_message(follow_up_content);
    }

    if !steering_content.is_empty() || !follow_up_content.is_empty() {
        self.scroll = 0;
        self.messages_changed();
    }
}

